SELECT emplyr_id AS id
FROM acm_member_mst
WHERE user_nm = #{name}
AND email_adres = #{email}
AND emplyr_sttus_code = 'P'

SELECT password AS password
FROM acm_member_mst
WHERE emplyr_id = #{id}
AND user_nm = #{name}
AND email_adres = #{email}
AND password_hint = #{passwordHint}
AND password_cnsr = #{passwordCnsr}
AND emplyr_sttus_code = 'P'

mapper.update:
UPDATE acm_member_mst
SET password = #{password}
WHERE emplyr_id = #{id}
